from flask import Flask, session, redirect, url_for, request
import requests

app = Flask(__name__)
app.secret_key = 'super secret key'
GOOGLE_AUTH_URL = 'https://accounts.google.com/o/oauth2/v2/auth'
GOOGLE_TOKEN_URL = 'https://oauth2.googleapis.com/token'

@app.route('/')
def index():
    return """
        <a href='{}?response_type=code&client_id={}&redirect_uri={}'.format(GOOGLE_AUTH_URL, 'YOUR_CLIENT_ID', url_for('callback'))>
            Log in with Google
        </a>
    """

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if code:
        token_url, headers, body = create_token_request(code)
        response = requests.post(token_url, headers=headers, data=body)
        credentials = response.json()
        session['credentials'] = credentials
        return redirect('/')
    else:
        return 'Invalid request'

def create_token_request(code):
    client_id = 'YOUR_CLIENT_ID'
    client_secret = 'YOUR_CLIENT_SECRET'
    redirect_uri = url_for('callback', _external=True)

    token_url = GOOGLE_TOKEN_URL + '?code={}&client_id={}&client_secret={}&redirect_uri={}&grant_type=authorization_code'.format(code, client_id, client_secret, redirect_uri)

    headers = {'Content-Type': 'application/x-www-form-urlencoded'}

    body = "client_id={}&client_secret={}&redirect_uri={}&grant_type=authorization_code&code=".format(client_id, client_secret, redirect_uri) + code

    return token_url, headers, body

if __name__ == '__main__':
    app.run()